mapper.select:
SELECT COUNT(1) FROM ( SELECT T1.*, '项目类型' as showSecondLable, '项目部门' as showThirdLable, T2.TODO_TASK_ID AS taskId , T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version, T3.PROJECT_NAME as projectName, T3.PROJECT_CODE as projectCode, T3.PROJECT_DEPT as projectDept, T3.PROJECT_TYPE_CODE as projectTypeCode, T3.PROJECT_TYPE as projectType, T3.PROJECT_CHARGER AS pmName, T3.PROJECT_NAME as showFirst, T3.PROJECT_DEPT as showThird, (CASE WHEN T1.ISSUED_TYPE = 1 THEN (CASE WHEN T3.PROJECT_TYPE = 1 THEN '开发类' WHEN T3.PROJECT_TYPE = 2 THEN '实施类' WHEN T3.PROJECT_TYPE = 3 THEN '产品销售类' WHEN T3.PROJECT_TYPE = 4 THEN '运维类' WHEN T3.PROJECT_TYPE = 5 THEN '技术服务类' WHEN T3.PROJECT_TYPE = 6 THEN '资源与租赁类' WHEN T3.PROJECT_TYPE = 7 THEN '研究与咨询类' WHEN T3.PROJECT_TYPE = 8 THEN '工程类' WHEN T3.PROJECT_TYPE = 9 THEN '科技创新类' END) WHEN T1.ISSUED_TYPE = 2 THEN (CASE WHEN T3.PROJECT_TYPE = 1 THEN '前期研究类' WHEN T3.PROJECT_TYPE = 2 THEN '信息系统开发类' WHEN T3.PROJECT_TYPE = 3 THEN '共享资源设施购置类' WHEN T3.PROJECT_TYPE = 4 THEN '信息系统维护类' WHEN T3.PROJECT_TYPE = 5 THEN '数据及集成服务类' WHEN T3.PROJECT_TYPE = 6 THEN '技术创新平台类' WHEN T3.PROJECT_TYPE = 7 THEN '技术研究类' WHEN T3.PROJECT_TYPE = 8 THEN '管理创新类' WHEN T3.PROJECT_TYPE = 9 THEN '技术咨询服务类' WHEN T3.PROJECT_TYPE = 10 THEN '产品开发类' WHEN T3.PROJECT_TYPE = 11 THEN '开发类' END) WHEN T1.ISSUED_TYPE =3 THEN (CASE WHEN T3.PROJECT_TYPE = 1 THEN '开发类' WHEN T3.PROJECT_TYPE = 2 THEN '实施类' WHEN T3.PROJECT_TYPE = 3 THEN '产品销售类' WHEN T3.PROJECT_TYPE = 4 THEN '运维类' WHEN T3.PROJECT_TYPE = 5 THEN '技术服务类' WHEN T3.PROJECT_TYPE = 6 THEN '资源与租赁类' WHEN T3.PROJECT_TYPE = 7 THEN '研究与咨询类' WHEN T3.PROJECT_TYPE = 8 THEN '工程类' WHEN T3.PROJECT_TYPE = 9 THEN '科技创新类' END) END) AS showSecond, T2.CREATE_TIME AS sortTime, CEIL(SYSDATE -CAST(T2.CREATE_TIME AS DATE)) AS stayTime FROM DM_PM_PROJECT_QUALITY T1, ${transTableName} T2, DM_PM_PROJECT T3 WHERE T1.PROCESS_INS_ID = T2.MAIN_PROCESS_INS_ID AND T1.FLOW_STATE = 1 AND T1.PROJECT_ID = T3.ID(+) AND T2.TRANS_ACTOR_ID = #{transActor} AND T2.MAIN_PROCESS_ID = #{processId}
AND T3.PROJECT_NAME like '%' || #{searchKeyNew}|| '%'
AND (T3.PROJECT_NAME like '%' || #{queryName}|| '%' or T3.PROJECT_CODE like '%' || #{queryName} ||'%')
AND T2.CUR_NODE_ID = #{nodeId}
AND T2.CREATE_TIME >= (sysdate - 1)
AND T2.CREATE_TIME < (sysdate - 1)
AND T2.CREATE_TIME < (sysdate - 3)
AND T2.CREATE_TIME < (sysdate - 7)
) t

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version, T3.PROJECT_NAME as projectName, T3.PROJECT_CODE as projectCode, T3.PROJECT_DEPT as projectDept, T3.PROJECT_TYPE_CODE as projectTypeCode, T3.PROJECT_TYPE as projectType, T3.PROJECT_CHARGER AS pmName FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME ) T2, DM_PM_PROJECT T3 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.PROJECT_ID = T3.ID(+)
AND T2.CUR_NODE_ID = #{nodeId}
ORDER BY
T1.${sortField.sortName} ${sortField.sortType}

SELECT COUNT(1) FROM (SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version, T3.PROJECT_NAME as projectName, T3.PROJECT_CODE as projectCode, T3.PROJECT_DEPT as projectDept, T3.PROJECT_TYPE_CODE as projectTypeCode, T3.PROJECT_TYPE as projectType, T3.PROJECT_CHARGER AS pmName FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME ) T2, DM_PM_PROJECT T3 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.PROJECT_ID = T3.ID(+)
AND T2.CUR_NODE_ID = #{nodeId}
) t

SELECT * FROM (SELECT BT.*, T2.TODO_TASK_ID taskId, NVL(T2.MAIN_PROCESS_ID, #{processId}) AS processId, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY BT LEFT JOIN (select * from ${transTableName} T3 where T3.TRANS_ACTOR_ID = #{transActor}) T2 ON BT.PROCESS_INS_ID = T2.MAIN_PROCESS_INS_ID WHERE (BT.FLOW_STATE = 0 OR BT.FLOW_STATE IS NULL)) T1 WHERE (T1.processId = #{processId} OR T1.processId IS NULL) AND ((T1.taskId is null and T1.process_ins_id is null) or (T1.taskId is not null and T1.process_ins_id is not null))
ORDER BY
T1.${sortField.sortName} ${sortField.sortType}

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5) AND T.MAIN_PROCESS_ID = #{processId} AND T.CUR_NODE_ID = #{nodeId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID
ORDER BY
T1.${sortField.sortName} ${sortField.sortType}

SELECT COUNT(1) FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.FLOW_STATE = 1

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.FLOW_STATE = 1
ORDER BY
T1.${sortField.sortName} ${sortField.sortType}

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.FLOW_STATE = 2
ORDER BY
T1.${sortField.sortName} ${sortField.sortType}

SELECT COUNT(1) FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.FLOW_STATE = 2

select * from (select * from DM_PM_PROJECT_QUALITY T5, (select distinct t2.cur_process_id as processId, t2.main_process_ins_id from ${ruNodeTrackTableName} t2 where t2.node_track_id in (select t3.node_track_id from ${ruTransTrackTableName} t3 where t3.actor_id = #{transActor}) and t2.cur_process_id = #{processId}) c where T5.process_ins_id = c.main_process_ins_id union select T4.*, null as processId, null as main_process_ins_id from DM_PM_PROJECT_QUALITY T4 where T4.process_ins_id is null ) T1
ORDER BY
T1.${sortField.sortName} ${sortField.sortType}

SELECT T1.*, T2.TODO_TASK_ID AS taskId , T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, ${transTableName} T2 WHERE T1.PROCESS_INS_ID = T2.MAIN_PROCESS_INS_ID AND T1.FLOW_STATE = 1 AND T2.TRANS_ACTOR_ID = #{transActor} AND T2.MAIN_PROCESS_ID = #{processId}
AND T2.CUR_NODE_ID = #{nodeId}
AND T1.${primaryName} = #{primaryValue}

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID
AND T2.CUR_NODE_ID = #{nodeId}
AND T1.${primaryName} = #{primaryValue}

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.FLOW_STATE = 1 AND T1.${primaryName} = #{primaryValue}

SELECT T1.*, T2.DONE_TASK_ID AS taskId, T2.REVOKE_BACK_FLAG as revokeBackFlag, T2.CUR_NODE_ID as nodeId, T2.CUR_NODE_NAME as nodeName, T2.BACK_FLAG as backFlag, T2.READ_FLAG as readFlag, T2.MAIN_PROCESS_ID as processId, T2.NOTE as opinion, T2.VERSION as version FROM DM_PM_PROJECT_QUALITY T1, (SELECT T1.* FROM ${transTableName} T1, (SELECT MAX(T.CREATE_TIME) AS MAXCREATETIME, T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID FROM ${transTableName} T WHERE (T.STATUS = 1 OR T.STATUS = 5 OR T.STATUS = 4 OR T.STATUS = 7) AND T.MAIN_PROCESS_ID = #{processId} AND T.TRANS_ACTOR_ID = #{transActor} GROUP BY T.MAIN_PROCESS_ID, T.VERSION, T.MAIN_PROCESS_INS_ID, T.TRANS_ACTOR_ID) TEMPTAB WHERE T1.MAIN_PROCESS_ID = TEMPTAB.MAIN_PROCESS_ID AND T1.VERSION = TEMPTAB.VERSION AND T1.MAIN_PROCESS_INS_ID = TEMPTAB.MAIN_PROCESS_INS_ID AND T1.TRANS_ACTOR_ID = TEMPTAB.TRANS_ACTOR_ID AND T1.CREATE_TIME = TEMPTAB.MAXCREATETIME
AND T1.CUR_NODE_ID NOT IN
#{item}
) T2 WHERE T2.MAIN_PROCESS_INS_ID = T1.PROCESS_INS_ID AND T1.FLOW_STATE = 2 AND T1.${primaryName} = #{primaryValue}

