select t1.id, t1.project_id as projectId, t2.project_name as projectName, t2.PROJECT_CODE as projectCode, t1.ISSUED_TYPE as issuedType, t2.PROJECT_TYPE as projectType , t2.PROJECT_DEPT as projectDept, t2.PROJECT_CHARGER as pmName, t1.QUALITY_STATUS as qualityStatus from DM_PM_PROJECT_QUALITY t1 left join DM_PM_PROJECT t2 on t1.PROJECT_ID = t2.ID WHERE t1.PROJECT_QUALITY_ID = #{loginUserId} and t1.quality_status in (3,4) and t1.is_deleted = 2 and t2.is_deleted = 2 and t2.phase_status != 1003 and not exists ( select 1 from DM_PM_PROJECT_TERMINATION t3 where t3.project_id = t1.PROJECT_ID and t3.flow_state = 2 and t3.is_deleted = 2 )
and t1.ISSUED_TYPE = #{issuedType}
and t2.project_name like '%' || #{projectName} || '%'
and t2.PROJECT_TYPE_CODE = #{projectTypeCode}
and t2.PROJECT_TYPE = #{projectType}
order by t1.CREATE_TIME desc

mapper.update:
    update DM_PM_PROJECT_QUALITY t1 
set t1.QUALITY_STATUS = #{qualityStatus}
where t1.id = #{id}

    BEGIN

update DM_PM_PROJECT_QUALITY t1 
